 * 设 $N$ 是字符串长度。
 * 
 * Case 1: 目标是全 '0' ("00...0")
 * Cost_0 = 字符串中 '1' 的数量。
 * 
 * Case 2: 目标是全 '1' ("11...1")
 * Cost_1 = 字符串中 '0' 的数量。
 * 
 * Case 3: 目标是 "0...01" (k 个 '0', 1 个 '1', $N-k-1$ 个 '0' 或 '1' 必须是 '0')
 * 由于连贯串最多只有一个 '1' 或一个 '0'，所以如果 $N>2$, 形式 "0...01" 意味着它必须是 $0^a 1^b$ 且 $b \le 1$.
 * 如果 $b=1$: 形式是 $0...01$. 
 * Cost_01: 尝试将 $S$ 变成 $0...01$. 
 *   - 找到一个位置 $p$ ($0 \le p < N$) 设为 '1'，其他 $N-1$ 个位置设为 '0'.
 *   - 最小成本是 $\min_{p=0}^{N-1} (\text{cost to make } S \text{ equal to } 0^{p}10^{N-1-p})$.
 *   - 成本计算：$\text{cost} = (\text{count of '1's in } S \text{ excluding } S[p]) + (\text{cost to change } S[p] \text{ to '1'})$.
 * 
 * Case 4: 目标是 "1...10"
 * 
 * 鉴于 $N$ 最大是 $10^5$，我们需要一个 $O(N)$ 或 $O(N \log N)$ 的解法。
 * 
 * 观察：如果 $S$ 连贯，它必须是 $0^a$ 或 $1^b$ 或 $0^a 1$ 或 $1 0^b$.
 * 
 * 1. 目标 $0^N$: Cost = count('1')
 * 2. 目标 $1^N$: Cost = count('0')
 * 
 * 3. 目标 $0^{N-1}1$ (即 $0$ 后面跟 $1$):
 *    选择一个位置 $p$ ($0 \le p < N$) 使得 $S[p]$ 变成 '1' 且其余 $S[i], i \ne p$ 变成 '0'.
 *    Cost for fixed $p$: $(\text{count of '1's in } S \text{ excluding } S[p]) + (S[p] == '0' ? 1 : 0)$.
 *    We want $\min_p (\dots)$.
 * 
 * 4. 目标 $10^{N-1}$ (即 $1$ 后面跟 $0$):
 *    选择一个位置 $p$ ($0 \le p < N$) 使得 $S[p]$ 变成 '1' 且其余 $S[i], i \ne p$ 变成 '0'.
 *    Wait, this is wrong. Target $10^{N-1}$ means $S[0]='1', S[i]='0'$ for $i>0$.
 *    Cost for fixed $p=0$: $(\text{count of '0's in } S \text{ excluding } S[0]) + (S[0] == '0' ? 1 : 0)$.
 *    Wait, this is just $10^{N-1}$.
 * 
 * Let's simplify the target structures based on the necessary structure $0^a 1$ or $1 0^b$.
 * 
 * Case A: All '0's: Cost = count('1')
 * Case B: All '1's: Cost = count('0')
 * 
 * Case C: $0...01$: One '1' at position $p$, others are '0'.
 * Cost = $\min_{0 \le p < N} \{ (\text{count of '1's in } S) - (S[p]=='1' ? 1 : 0) + (S[p]=='0' ? 1 : 0) \}$
 * 
 * Case D: $10...0$: One '1' at position $p$, others are '0'. Wait, this is covered by Case C.
 * The structures are:
 * 1. $0^N$
 * 2. $1^N$
 * 3. $0^a 1$ (where $a \ge 0$)
 * 4. $1 0^b$ (where $b \ge 0$)
 * 
 * Wait, if $a=0$, Case 3 is $1$ (covered by Case B). If $b=0$, Case 4 is $1$ (covered by Case B).
 * If $a=N-1$, Case 3 is $0^{N-1}1$.
 * If $b=N-1$, Case 4 is $10^{N-1}$.
 * 
 * We need to check $0^N$, $1^N$, $0^{N-1}1$, $10^{N-1}$ (and $01, 10$ which are covered).
 * 
 * Let $C_0 = \text{count}('1')$ (Cost to make all '0').
 * Let $C_1 = \text{count}('0')$ (Cost to make all '1').
 * 
 * $C_{01}$: Min cost to achieve $0...01$.
 * We iterate over $p \in [0, N-1]$. Target is $T_p = 0^{p}10^{N-1-p}$.
 * Cost for $T_p$: Count mismatches between $S$ and $T_p$.
 * $T_p[p] = '1'$, $T_p[i] = '0'$ for $i \ne p$.
 * Cost = $(S[p] == '0' ? 1 : 0) + \sum_{i \ne p} (S[i] == '1' ? 1 : 0)$.
 * This is equivalent to: Cost = (Total count of '1's) - ($S[p]=='1' ? 1 : 0$) + ($S[p]=='0' ? 1 : 0$).
 * 
 * $C_{10}$: Min cost to achieve $10...0$.
 * We iterate over $p \in [0, N-1]$. Target is $T_p = 10^{p-1}0^{N-p}$. Wait, this is confusing.
 * Let's stick to the two simplest structures involving one switch:
 * 1. $0...01$: Target has one '1' at $p$. Cost $C_{01, p}$.
 * 2. $10...0$: Target has one '1' at $p$. Cost $C_{10, p}$. Wait, this is the same structure.
 * 
 * The set of target structures is:
 * 1. $0^N$
 * 2. $1^N$
 * 3. $0^a 1$ ($0 \le a < N$): One '1', others '0'.
 * 4. $10^b$ ($0 \le b < N$): One '1' at index 0, others '0'. This is a subset of 3 if we allow $a=0$.
 * 
 * Let's check all $N$ possible positions for a single '1' (and rest '0'), and $N$ possible positions for a single '0' (and rest '1').
 * 
 * Set of candidates $T$:
 * 1. $0^N$
 * 2. $1^N$
 * 3. $T_p$: string with '1' at $p$, '0' elsewhere ($N$ options)
 * 4. $R_p$: string with '0' at $p$, '1' elsewhere ($N$ options)
 * 
 * Case 3 ($T_p$): Cost to change $S$ to $T_p$.
 * $C_{T_p} = (S[p] == '0' ? 1 : 0) + \sum_{i \ne p} (S[i] == '1' ? 1 : 0)$.
 * $\min C_{T_p}$ gives the minimum cost to have exactly one '1' (or zero '1's if $N=1$). This covers $0...01$ (if $p>0$) and $1$ (if $p=0$).
 * 
 * Case 4 ($R_p$): Cost to change $S$ to $R_p$.
 * $C_{R_p} = (S[p] == '1' ? 1 : 0) + \sum_{i \ne p} (S[i] == '0' ? 1 : 0)$.
 * $\min C_{R_p}$ gives the minimum cost to have exactly one '0' (or zero '0's if $N=1$). This covers $0^N$ (if $p=N-1$) and $0$ (if $p=N-1$).
 * 
 * Total minimum cost = $\min(C_0, C_1, \min_p C_{T_p}, \min_p C_{R_p})$.
 * 
 * We can precalculate prefix sums of '0's and '1's to calculate these costs in $O(1)$ for each $p$, leading to an $O(N)$ solution.
 */
class Solution {
public:
    long long solve(string s) {
        int n = s.length();
        if (n <= 3) {
            // For small N, brute force checking all 2^N strings or direct simulation is fine, 
            // but the general O(N) approach should handle it. Let's stick to the derived logic.
        }

        // Precalculate counts
        int count_0 = 0;
        int count_1 = 0;
        for (char c : s) {
            if (c == '0') count_0++;
            else count_1++;
        }

        // Case 1: Target is all '0's (0^N)
        long long min_cost = count_1;

        // Case 2: Target is all '1's (1^N)
        min_cost = min(min_cost, (long long)count_0);

        // Precalculate prefix sums for '1's and '0's
        // prefix_1[i] = count of '1's in s[0...i-1]
        vector<int> prefix_1(n + 1, 0);
        vector<int> prefix_0(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            prefix_1[i + 1] = prefix_1[i] + (s[i] == '1' ? 1 : 0);
            prefix_0[i + 1] = prefix_0[i] + (s[i] == '0' ? 1 : 0);
        }

        // Case 3: Target T_p: one '1' at p, others '0'. (Covers 0...01)
        // Cost = (S[p] == '0' ? 1 : 0) + (Total '1's - S[p]=='1' ? 1 : 0)
        for (int p = 0; p < n; ++p) {
            // Cost to make S[p] = '1'
            int cost_p_to_1 = (s[p] == '0' ? 1 : 0);

            // Cost to make S[i] = '0' for i != p
            // Sum of (S[i] == '1' ? 1 : 0) for i != p
            int ones_not_at_p = count_1 - (s[p] == '1' ? 1 : 0);

            long long current_cost = cost_p_to_1 + ones_not_at_p;
            min_cost = min(min_cost, current_cost);
        }

        // Case 4: Target R_p: one '0' at p, others '1'. (Covers 1...10)
        // Cost = (S[p] == '1' ? 1 : 0) + (Total '0's - S[p]=='0' ? 1 : 0)
        for (int p = 0; p < n; ++p) {
            // Cost to make S[p] = '0'
            int cost_p_to_0 = (s[p] == '1' ? 1 : 0);

            // Cost to make S[i] = '1' for i != p
            // Sum of (S[i] == '0' ? 1 : 0) for i != p
            int zeros_not_at_p = count_0 - (s[p] == '0' ? 1 : 0);

            long long current_cost = cost_p_to_0 + zeros_not_at_p;
            min_cost = min(min_cost, current_cost);
        }

        return min_cost;
    }
};

// Wrapper function to match required signature
long long solve(string s) {
    Solution sol;
    return sol.solve(s);
}
