#include <string>
#include <algorithm>
#include <vector>

using namespace std;

/**
 * @brief 检查一个字符串是否连贯。
 * 连贯的定义是不包含 "011" 或 "110" 作为子序列。
 * 
 * @param s 输入的二进制字符串。
 * @return true 如果字符串连贯，false 否则。
 */
bool is_coherent(const string& s) {
    int n = s.length();
    // 检查 "011" 子序列
    // 寻找 i < j < k 使得 s[i]='0', s[j]='1', s[k]='1'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            for (int j = i + 1; j < n; ++j) {
                if (s[j] == '1') {
                    for (int k = j + 1; k < n; ++k) {
                        if (s[k] == '1') {
                            return false; // 包含 "011"
                        }
                    }
                }
            }
        }
    }

    // 检查 "110" 子序列
    // 寻找 i < j < k 使得 s[i]='1', s[j]='1', s[k]='0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            for (int j = i + 1; j < n; ++j) {
                if (s[j] == '1') {
                    for (int k = j + 1; k < n; ++k) {
                        if (s[k] == '0') {
                            return false; // 包含 "110"
                        }
                    }
                }
            }
        }
    }

    return true;
}

/**
 * @brief 解决主问题。
