            int cost_p_to_1 = (s[p] == '0' ? 1 : 0);

            // Cost to make S[i] = '0' for i != p
            // Sum of (S[i] == '1' ? 1 : 0) for i != p
            int ones_not_at_p = count_1 - (s[p] == '1' ? 1 : 0);

            long long current_cost = cost_p_to_1 + ones_not_at_p;
            min_cost = min(min_cost, current_cost);
        }

        // Case 4: Target R_p: one '0' at p, others '1'. (Covers 1...10)
        // Cost = (S[p] == '1' ? 1 : 0) + (Total '0's - S[p]=='0' ? 1 : 0)
        for (int p = 0; p < n; ++p) {
            // Cost to make S[p] = '0'
            int cost_p_to_0 = (s[p] == '1' ? 1 : 0);

            // Cost to make S[i] = '1' for i != p
            // Sum of (S[i] == '0' ? 1 : 0) for i != p
            int zeros_not_at_p = count_0 - (s[p] == '0' ? 1 : 0);

            long long current_cost = cost_p_to_0 + zeros_not_at_p;
            min_cost = min(min_cost, current_cost);
        }

        return min_cost;
    }
};

// Wrapper function to match required signature
long long solve(string s) {
    Solution sol;
    return sol.solve(s);
}
